// MARK: - Models
struct Stock: Codable {
    let symbol: String
    let name: String
    let currentPrice: Double
    let change: Double
    let changePercent: Double
}

struct PortfolioItem: Codable {
    let symbol: String
    let quantity: Double
    let averageBuyPrice: Double
    var currentPrice: Double
}

struct Transaction: Codable {
    let id: String
    let symbol: String
    let type: TransactionType
    let quantity: Double
    let price: Double
    let timestamp: Date
}

enum TransactionType: String, Codable {
    case buy
    case sell
}

// MARK: - API Service
class TradingAPIService {
    static let shared = TradingAPIService()
    private let apiKey = "YOUR_API_KEY"
    private let baseURL = "https://api.example.com"
    
    private init() {}
    
    func fetchStocks(completion: @escaping (Result<[Stock], Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/stocks") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let stocks = try JSONDecoder().decode([Stock].self, from: data)
                completion(.success(stocks))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func executeTrade(_ transaction: Transaction, completion: @escaping (Result<Transaction, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/transactions") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        
        do {
            let jsonData = try JSONEncoder().encode(transaction)
            request.httpBody = jsonData
        } catch {
            completion(.failure(error))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let transaction = try JSONDecoder().decode(Transaction.self, from: data)
                completion(.success(transaction))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
}

// MARK: - Network Errors
enum NetworkError: Error {
    case invalidURL
    case noData
    case invalidResponse
}

// MARK: - Trade Execution Manager
class TradeExecutionManager {
    static let shared = TradeExecutionManager()
    private let apiService = TradingAPIService.shared
    private var cancellables = Set<AnyCancellable>()
    
    func executeBuy(symbol: String, quantity: Double, completion: @escaping (Result<Transaction, Error>) -> Void) {
        apiService.fetchStocks { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let stocks):
                guard let stock = stocks.first(where: { $0.symbol == symbol }) else {
                    completion(.failure(NetworkError.invalidResponse))
                    return
                }
                
                let transaction = Transaction(
                    id: UUID().uuidString,
                    symbol: symbol,
                    type: .buy,
                    quantity: quantity,
                    price: stock.currentPrice,
                    timestamp: Date()
                )
                
                self.apiService.executeTrade(transaction) { tradeResult in
                    completion(tradeResult)
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func executeSell(symbol: String, quantity: Double, completion: @escaping (Result<Transaction, Error>) -> Void) {
        apiService.fetchStocks { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let stocks):
                guard let stock = stocks.first(where: { $0.symbol == symbol }) else {
                    completion(.failure(NetworkError.invalidResponse))
                    return
                }
                
                let transaction = Transaction(
                    id: UUID().uuidString,
                    symbol: symbol,
                    type: .sell,
                    quantity: quantity,
                    price: stock.currentPrice,
                    timestamp: Date()
                )
                
                self.apiService.executeTrade(transaction) { tradeResult in
                    completion(tradeResult)
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
}

// MARK: - Portfolio Manager
class PortfolioManager {
    static let shared = PortfolioManager()
    private let userDefaults = UserDefaults.standard
    private let portfolioKey = "userPortfolio"
    
    private init() {}
    
    func loadPortfolio() -> [PortfolioItem] {
        guard let data = userDefaults.data(forKey: portfolioKey),
              let portfolio = try? JSONDecoder().decode([PortfolioItem].self, from: data) else {
            return []
        }
        return portfolio
    }
    
    func savePortfolio(_ portfolio: [PortfolioItem]) {
        if let data = try? JSONEncoder().encode(portfolio) {
            userDefaults.set(data, forKey: portfolioKey)
        }
    }
    
    func updatePortfolio(with transaction: Transaction) {
        var portfolio = loadPortfolio()
        let existingItem = portfolio.first { $0.symbol == transaction.symbol }
        
        if transaction.type == .buy {
            if let index = portfolio.firstIndex(where: { $0.symbol == transaction.symbol }) {
                let item = portfolio[index]
                let totalQuantity = item.quantity + transaction.quantity
                let newAveragePrice = ((item.averageBuyPrice * item.quantity) + (transaction.price * transaction.quantity)) / totalQuantity
                portfolio[index] = PortfolioItem(symbol: item.symbol, quantity: totalQuantity, averageBuyPrice: newAveragePrice, currentPrice: transaction.price)
            } else {
                portfolio.append(PortfolioItem(symbol: transaction.symbol, quantity: transaction.quantity, averageBuyPrice: transaction.price, currentPrice: transaction.price))
            }
        } else if transaction.type == .sell {
            if let index = portfolio.firstIndex(where: { $0.symbol == transaction.symbol }) {
                let item = portfolio[index]
                let newQuantity = item.quantity - transaction.quantity
                
                if newQuantity <= 0 {
                    portfolio.remove(at: index)
                } else {
                    portfolio[index] = PortfolioItem(symbol: item.symbol, quantity: newQuantity, averageBuyPrice: item.averageBuyPrice, currentPrice: transaction.price)
                }
            }
        }
        
        savePortfolio(portfolio)
    }
}

// MARK: - Main View Controller
class TradingViewController: UIViewController {
    @IBOutlet weak var tableView: UITableView!
    @IBOutlet weak var portfolioValueLabel: UILabel!
    @IBOutlet weak var balanceLabel: UILabel!
    
    private var stocks: [Stock] = []
    private var portfolio: [PortfolioItem] = []
    private let tradeManager = TradeExecutionManager.shared
    private let portfolioManager = PortfolioManager.shared
    private let apiService = TradingAPIService.shared
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupTableView()
        fetchStocks()
        loadPortfolio()
    }
    
    private func setupUI() {
        title = "Trading Platform"
        view.backgroundColor = .systemBackground
        
        let refreshControl = UIRefreshControl()
        refreshControl.addTarget(self, action: #selector(refreshData), for: .valueChanged)
        tableView.refreshControl = refreshControl
        
        let portfolioButton = UIBarButtonItem(title: "Portfolio", style: .plain, target: self, action: #selector(showPortfolio))
        navigationItem.rightBarButtonItem = portfolioButton
    }
    
    private func setupTableView() {
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "StockCell")
    }
    
    private func fetchStocks() {
        apiService.fetchStocks { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let stocks):
                    self?.stocks = stocks
                    self?.tableView.reloadData()
                case .failure(let error):
                    print("Error fetching stocks: \(error)")
                }
            }
        }
    }
    
    private func loadPortfolio() {
        portfolio = portfolioManager.loadPortfolio()
        updatePortfolioSummary()
    }
    
    private func updatePortfolioSummary() {
        let totalValue = portfolio.reduce(0.0) { $0 + ($1.quantity * $1.currentPrice) }
        portfolioValueLabel.text = String(format: "$%.2f", totalValue)
        
        // Simulate balance
        balanceLabel.text = "$10,000.00"
    }
    
    @objc private func refreshData() {
        fetchStocks()
        tableView.refreshControl?.endRefreshing()
    }
    
    @objc private func showPortfolio() {
        let portfolioVC = PortfolioViewController()
        portfolioVC.portfolio = portfolio
        let navController = UINavigationController(rootViewController: portfolioVC)
        present(navController, animated: true)
    }
}

// MARK: - Table View Data Source
extension TradingViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        stocks.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "StockCell", for: indexPath)
        let stock = stocks[indexPath.row]
        
        cell.textLabel?.text = "\(stock.symbol) - \(stock.name)"
        cell.detailTextLabel?.text = String(format: "$%.2f (%.2f%%)", stock.currentPrice, stock.changePercent)
        
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let stock = stocks[indexPath.row]
        
        let actionSheet = UIAlertController(title: stock.symbol, message: "Buy or sell \(stock.symbol)?", preferredStyle: .actionSheet)
        
        actionSheet.addAction(UIAlertAction(title: "Buy", style: .default) { _ in
            self.showQuantityInput(for: stock, type: .buy)
        })
        
        actionSheet.addAction(UIAlertAction(title: "Sell", style: .default) { _ in
            self.showQuantityInput(for: stock, type: .sell)
        })
        
        actionSheet.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(actionSheet, animated: true)
    }
    
    private func showQuantityInput(for stock: Stock, type: TransactionType) {
        let alert = UIAlertController(title: "\(type.rawValue.capitalized) \(stock.symbol)", message: "Enter quantity", preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Quantity"
            textField.keyboardType = .numberPad
        }
        
        alert.addAction(UIAlertAction(title: "Submit", style: .default) { _ in
            if let textField = alert.textFields?.first,
               let quantityText = textField.text,
               let quantity = Double(quantityText) {
                self.executeTrade(for: stock, type: type, quantity: quantity)
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
    
    private func executeTrade(for stock: Stock, type: TransactionType, quantity: Double) {
        if type == .buy {
            tradeManager.executeBuy(symbol: stock.symbol, quantity: quantity) { [weak self] result in
                DispatchQueue.main.async {
                    switch result {
                    case .success(let transaction):
                        self?.portfolioManager.updatePortfolio(with: transaction)
                        self?.loadPortfolio()
                        self?.showAlert(title: "Trade Executed", message: "Successfully bought \(quantity) shares of \(stock.symbol)")
                    case .failure(let error):
                        self?.showAlert(title: "Error", message: error.localizedDescription)
                    }
                }
            }
        } else {
            tradeManager.executeSell(symbol: stock.symbol, quantity: quantity) { [weak self] result in
                DispatchQueue.main.async {
                    switch result {
                    case .success(let transaction):
                        self?.portfolioManager.updatePortfolio(with: transaction)
                        self?.loadPortfolio()
                        self?.showAlert(title: "Trade Executed", message: "Successfully sold \(quantity) shares of \(stock.symbol)")
                    case .failure(let error):
                        self?.showAlert(title: "Error", message: error.localizedDescription)
                    }
                }
            }
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

